############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "contextForm.pl", "contextLimitedRadical.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
